
from Crypto.Cipher import AES
from Crypto.Util.Padding import unpad
import base64

KUNCI = b'RahasiaKu1234567'

def dekripsi_teks(data_terenkripsi):
    data = base64.b64decode(data_terenkripsi)
    iv = data[:16]
    isi = data[16:]
    cipher = AES.new(KUNCI, AES.MODE_CBC, iv)
    return unpad(cipher.decrypt(isi), AES.block_size).decode('utf-8')

# Kode terenkripsi
kode_rahasia = ""

# Jalankan kode setelah dibuka
exec(dekripsi_teks(kode_rahasia))
